currentprojection = perspective(6,3,2);

triple A, B, C, D, M, O;

A = (-1/sqrt(55),0,3*sqrt(6)/sqrt(55));
B = (sqrt(5/11), -sqrt(6/11), 0);
C = (sqrt(5/11), sqrt(6/11), 0);
D = (-1/sqrt(55),0,-3*sqrt(6)/sqrt(55));
O = (0,0,0);
M = (B + C)/2;

draw(O--A,dashed);
draw(O--B,dashed);
draw(O--C,dashed);
draw(O--D,dashed);
draw(A--B--D--C--cycle);
draw(B--C);
draw(A--M);
draw(M--O,dashed);

label("$A$", A, N);
label("$B$", B, W);
label("$C$", C, SE);
label("$D$", D, S);
label("$M$", M, S);
label("$O$", O, NW);
